// Priority-based sorting and processing logic
const items = $input.all();

// Sort by Priority (ascending) then by Last_Updated (ascending)
const sortedItems = items.sort((a, b) => {
  const priorityA = parseInt(a.json.Priority) || 999;
  const priorityB = parseInt(b.json.Priority) || 999;

  if (priorityA !== priorityB) {
    return priorityA - priorityB;
  }

  // If same priority, sort by last updated (oldest first)
  const dateA = new Date(a.json.Last_Updated || '1970-01-01');
  const dateB = new Date(b.json.Last_Updated || '1970-01-01');
  return dateA - dateB;
});

// Process only the highest priority item to avoid overwhelming the system
const itemToProcess = sortedItems[0];

if (!itemToProcess) {
  return [];
}

// Add processing metadata
itemToProcess.json.processedAt = new Date().toISOString();
itemToProcess.json.rowNumber = items.findIndex(item => 
  item.json.Brand_Name === itemToProcess.json.Brand_Name && 
  item.json.Series_Name === itemToProcess.json.Series_Name
) + 2; // +2 because row 1 is headers and arrays are 0-indexed

return [itemToProcess];

// Brand configuration and content processing
const masterControl = $input.first().json;
const contentItems = $input.all().slice(1); // Skip the master control item

if (contentItems.length === 0) {
  throw new Error(`No ready content found in sheet: ${masterControl.SheetName}`);
}

// Select the first ready content item
const contentItem = contentItems[0].json;

// Brand-specific configurations
const brandConfigs = {
  'Dax the Traveler': {
    voiceId: 'pNInz6obpgDQGcFmaJgB',
    style: 'personal travel experiences and adventures',
    audience: 'travel enthusiasts and adventure seekers',
    tone: 'adventurous, inspiring, and authentic',
    hashtagStyle: '#travel #adventure #explore #wanderlust #daxtheTraveler'
  },
  'God\'s Vessel': {
    voiceId: 'EXAVITQu4vr4xnSDxMaL',
    style: 'faith-based inspiration and biblical wisdom',
    audience: 'Christian community and faith seekers',
    tone: 'uplifting, spiritual, and encouraging',
    hashtagStyle: '#faith #christian #bible #inspiration #godsvessel'
  },
  'Ani-Dax': {
    voiceId: 'pNInz6obpgDQGcFmaJgB',
    style: 'anime analysis, character breakdowns, and hype content',
    audience: 'anime fans and otaku community',
    tone: 'energetic, passionate, and knowledgeable',
    hashtagStyle: '#anime #manga #otaku #animeanalysis #anidax'
  },
  'Time-Zone Travelers': {
    voiceId: 'pNInz6obpgDQGcFmaJgB',
    style: 'practical travel tips, hacks, and budget advice',
    audience: 'budget travelers and travel planners',
    tone: 'helpful, practical, and informative',
    hashtagStyle: '#traveltips #budgettravel #travelhacks #timezonetravelers'
  }
};

const brandConfig = brandConfigs[masterControl.Brand_Name] || brandConfigs['Dax the Traveler'];

// Content optimization based on type
const contentOptimization = {
  'Shorts': {
    duration: '30-60 seconds',
    format: 'vertical 9:16',
    style: 'fast-paced, hook-heavy, trending',
    platform: 'YouTube Shorts, TikTok, Instagram Reels'
  },
  'Long-form': {
    duration: '5-15 minutes',
    format: 'horizontal 16:9',
    style: 'educational, detailed, storytelling',
    platform: 'YouTube main feed'
  },
  'Social': {
    duration: '15-30 seconds',
    format: 'square 1:1',
    style: 'engaging, shareable, text-overlay',
    platform: 'Instagram, Facebook, Twitter'
  }
};

const contentConfig = contentOptimization[masterControl.Content_Type] || contentOptimization['Shorts'];

return {
  json: {
    // Master Control Data
    masterControl: masterControl,

    // Content Data
    contentPrompt: contentItem.Prompt || contentItem['Video Prompt'] || contentItem.Content || contentItem.Title,
    contentDescription: contentItem.Description || '',

    // Brand Configuration
    brandConfig: brandConfig,
    contentConfig: contentConfig,

    // Processing Metadata
    processedAt: new Date().toISOString(),
    contentRowNumber: 2, // Will be updated based on actual row

    // YouTube Metadata
    youtubeChannelId: masterControl.YouTube_Channel_ID,
    videoTitle: `${masterControl.Series_Name}: ${contentItem.Prompt || contentItem.Title || 'New Content'}`,
    videoDescription: `${contentItem.Description || contentItem.Prompt || ''} \n\n${brandConfig.hashtagStyle}`,
    videoTags: masterControl.Series_Name.split(' ').concat(masterControl.Brand_Name.split(' '))
  }
};

