// Process the generated script and extract components
const response = $input.first().json;
const script = response.choices[0].message.content;
const masterControl = $input.first().json.masterControl;
const brandConfig = $input.first().json.brandConfig;
const contentConfig = $input.first().json.contentConfig;

// Extract visual prompts from script
const visualPrompts = [];
const lines = script.split('\n');

for (const line of lines) {
  const visualMatch = line.match(/\[VISUAL:([^\]]+)\]/);
  if (visualMatch) {
    visualPrompts.push(visualMatch[1].trim());
  }
}

// If no visual prompts found, create default ones based on brand and content
if (visualPrompts.length === 0) {
  const defaultVisuals = {
    'Dax the Traveler': 'stunning travel destination, adventure scene, beautiful landscape',
    'God\'s Vessel': 'peaceful spiritual scene, nature with soft lighting, inspirational background',
    'Ani-Dax': 'dynamic anime-style scene, colorful animation background, character focus',
    'Time-Zone Travelers': 'travel planning scene, world map, travel essentials'
  };

  visualPrompts.push(defaultVisuals[masterControl.Brand_Name] || defaultVisuals['Dax the Traveler']);
}

// Clean script for audio (remove visual tags)
const audioText = script
  .replace(/\[VISUAL:[^\]]+\]/g, '')
  .replace(/Scene \d+:/g, '')
  .replace(/\n\n+/g, '\n')
  .trim();

// Create video metadata
const videoMetadata = {
  title: `${masterControl.Series_Name}: ${$input.first().json.contentPrompt.substring(0, 50)}...`,
  description: `${$input.first().json.contentDescription || $input.first().json.contentPrompt}\n\n${brandConfig.hashtagStyle}\n\nCreated with Dax Collective Automation`,
  tags: [
    masterControl.Brand_Name.replace(/[^a-zA-Z0-9]/g, ''),
    masterControl.Series_Name.replace(/[^a-zA-Z0-9]/g, ''),
    masterControl.Content_Type,
    'automation',
    'ai'
  ],
  categoryId: '22', // People & Blogs
  privacyStatus: 'public'
};

return {
  json: {
    // Original data
    masterControl: masterControl,
    brandConfig: brandConfig,
    contentConfig: contentConfig,

    // Generated content
    fullScript: script,
    audioText: audioText,
    visualPrompts: visualPrompts,

    // Video metadata
    videoMetadata: videoMetadata,

    // Processing info
    processedAt: new Date().toISOString(),
    scriptLength: audioText.length,
    visualCount: visualPrompts.length
  }
};

// Combine visual and audio assets for video creation
const scriptData = $input.first().json;
const visualData = $input.all()[1].json;
const audioData = $input.all()[2].json;

// Select best visual from Pexels results
let selectedVisual = null;
if (visualData.videos && visualData.videos.length > 0) {
  // Prefer HD quality videos
  selectedVisual = visualData.videos.find(video => 
    video.video_files.some(file => file.quality === 'hd')
  ) || visualData.videos[0];
}

// Get the best quality video file
let videoUrl = null;
if (selectedVisual) {
  const hdFile = selectedVisual.video_files.find(file => file.quality === 'hd');
  const sdFile = selectedVisual.video_files.find(file => file.quality === 'sd');
  videoUrl = (hdFile || sdFile || selectedVisual.video_files[0]).link;
}

const combinedAssets = {
  // Video assets
  visualUrl: videoUrl,
  visualDuration: selectedVisual ? selectedVisual.duration : 30,
  visualId: selectedVisual ? selectedVisual.id : null,

  // Audio assets
  audioData: audioData,
  audioText: scriptData.audioText,

  // Metadata
  masterControl: scriptData.masterControl,
  videoMetadata: scriptData.videoMetadata,
  brandConfig: scriptData.brandConfig,
  contentConfig: scriptData.contentConfig,

  // Processing info
  combinedAt: new Date().toISOString(),
  readyForAssembly: !!(videoUrl && audioData)
};

if (!combinedAssets.readyForAssembly) {
  throw new Error('Missing required assets for video assembly');
}

return { json: combinedAssets };
